1	const TOKEN_KEY = "auth-token";
2	
3	function getToken(): string | null {
4	  if (typeof window === "undefined") return null;
5	  return localStorage.getItem(TOKEN_KEY);
6	}
7	
8	export function setToken(token: string) {
9	  localStorage.setItem(TOKEN_KEY, token);
10	}
11	
12	export function clearToken() {
13	  localStorage.removeItem(TOKEN_KEY);
14	}
15	
16	export async function apiFetch<T = unknown>(
17	  url: string,
18	  options: RequestInit = {},
19	): Promise<T> {
20	  const token = getToken();
21	  const headers: Record<string, string> = {
22	    "Content-Type": "application/json",
23	    ...((options.headers as Record<string, string>) || {}),
24	  };
25	  if (token) headers["Authorization"] = `Bearer ${token}`;
26	
27	  const res = await fetch(url, {
28	    ...options,
29	    headers,
30	  });
31	
32	  if (res.status === 401) {
33	    clearToken();
34	  }
35	
36	  if (!res.ok) {
37	    const body = await res.json().catch(() => ({}));
38	    throw new ApiError(res.status, body.error || body.message || res.statusText);
39	  }
40	
41	  return res.json() as Promise<T>;
42	}
43	
44	export class ApiError extends Error {
45	  constructor(
46	    public status: number,
47	    message: string,
48	  ) {
49	    super(message);
50	    this.name = "ApiError";
51	  }
52	}
