1	import { cn } from "@/lib/utils";
2	import { CheckCircle2, Circle, Clock, XCircle } from "lucide-react";
3	
4	type TimelineEventStatus = "completed" | "current" | "pending" | "rejected" | "cancelled";
5	
6	interface TimelineEvent {
7	  id: string;
8	  status: TimelineEventStatus;
9	  title: string;
10	  description?: string;
11	  timestamp?: string;
12	  actor?: string;
13	}
14	
15	interface TicketTimelineProps {
16	  events: TimelineEvent[];
17	  className?: string;
18	}
19	
20	const statusIcon = {
21	  completed: CheckCircle2,
22	  current: Clock,
23	  pending: Circle,
24	  rejected: XCircle,
25	  cancelled: XCircle,
26	};
27	
28	const statusColors = {
29	  completed: "text-success",
30	  current: "text-primary",
31	  pending: "text-muted-foreground",
32	  rejected: "text-destructive",
33	  cancelled: "text-muted-foreground",
34	};
35	
36	const lineColors = {
37	  completed: "bg-success",
38	  current: "bg-primary",
39	  pending: "bg-border",
40	  rejected: "bg-destructive",
41	  cancelled: "bg-border",
42	};
43	
44	export default function TicketTimeline({ events, className }: TicketTimelineProps) {
45	  if (events.length === 0) {
46	    return (
47	      <div className="text-sm text-muted-foreground text-center py-8">
48	        暂无时间轴记录
49	      </div>
50	    );
51	  }
52	
53	  return (
54	    <div className={cn("space-y-0", className)}>
55	      {events.map((event, index) => {
56	        const Icon = statusIcon[event.status];
57	        const isLast = index === events.length - 1;
58	
59	        return (
60	          <div key={event.id} className="flex gap-4">
61	            {/* Timeline line + icon */}
62	            <div className="flex flex-col items-center">
63	              <div className={cn(
64	                "rounded-full p-0.5",
65	                statusColors[event.status]
66	              )}>
67	                <Icon className="w-5 h-5" />
68	              </div>
69	              {!isLast && (
70	                <div className={cn(
71	                  "w-0.5 flex-1 min-h-8",
72	                  lineColors[event.status]
73	                )} />
74	              )}
75	            </div>
76	
77	            {/* Content */}
78	            <div className={cn("pb-6 flex-1", isLast && "pb-0")}>
79	              <p className={cn(
80	                "text-sm font-medium",
81	                event.status === "pending" && "text-muted-foreground"
82	              )}>
83	                {event.title}
84	              </p>
85	              {event.description && (
86	                <p className="text-sm text-muted-foreground mt-0.5">{event.description}</p>
87	              )}
88	              {(event.timestamp || event.actor) && (
89	                <div className="flex items-center gap-2 mt-1">
90	                  {event.timestamp && (
91	                    <span className="text-xs text-muted-foreground">{event.timestamp}</span>
92	                  )}
93	                  {event.actor && (
94	                    <span className="text-xs text-muted-foreground">by {event.actor}</span>
95	                  )}
96	                </div>
97	              )}
98	            </div>
99	          </div>
100	        );
101	      })}
102	    </div>
103	  );
104	}
105	
106	export type { TimelineEvent, TimelineEventStatus };
