1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError } from "@/lib/auth";
4	import type { TicketStatus } from "@prisma/client";
5	
6	export async function GET(request: NextRequest) {
7	  try {
8	    const user = await verifyAuth(request);
9	    const { searchParams } = new URL(request.url);
10	    const page = Math.max(1, parseInt(searchParams.get("page") || "1", 10));
11	    const limit = Math.min(50, Math.max(1, parseInt(searchParams.get("limit") || "20", 10)));
12	    const skip = (page - 1) * limit;
13	
14	    if (user.role === "MANAGER") {
15	      // Manager: approved/rejected tickets from their department (excluding self)
16	      const where = {
17	        applicant: { deptId: user.deptId },
18	        applicantId: { not: user.userId },
19	        status: { in: ["APPROVED", "REJECTED", "COMPLETED", "IN_PROGRESS"] as TicketStatus[] },
20	      };
21	
22	      const [tickets, total] = await Promise.all([
23	        prisma.ticket.findMany({
24	          where: where as any,
25	          orderBy: { updatedAt: "desc" },
26	          skip,
27	          take: limit,
28	          include: {
29	            applicant: { select: { id: true, name: true, email: true } },
30	            targetAsset: { include: { model: true } },
31	            targetModel: true,
32	          },
33	        }),
34	        prisma.ticket.count({ where: where as any }),
35	      ]);
36	
37	      return Response.json({
38	        tickets,
39	        pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
40	      });
41	    }
42	
43	    if (user.role === "IT_ADMIN") {
44	      // IT Admin: all tickets that have passed PENDING_IT
45	      const where = {
46	        status: { in: ["APPROVED", "REJECTED", "IN_PROGRESS", "COMPLETED"] as TicketStatus[] },
47	      };
48	
49	      const [tickets, total] = await Promise.all([
50	        prisma.ticket.findMany({
51	          where,
52	          orderBy: { updatedAt: "desc" },
53	          skip,
54	          take: limit,
55	          include: {
56	            applicant: { select: { id: true, name: true, email: true } },
57	            targetAsset: { include: { model: true } },
58	            targetModel: true,
59	          },
60	        }),
61	        prisma.ticket.count({ where }),
62	      ]);
63	
64	      return Response.json({
65	        tickets,
66	        pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
67	      });
68	    }
69	
70	    return Response.json({ error: "No approval history for your role" }, { status: 403 });
71	  } catch (e) {
72	    if (e instanceof AuthError) {
73	      return Response.json({ error: e.message }, { status: e.statusCode });
74	    }
75	    return Response.json({ error: "Internal server error" }, { status: 500 });
76	  }
77	}
