1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError } from "@/lib/auth";
4	
5	export async function GET(request: NextRequest) {
6	  try {
7	    const user = await verifyAuth(request);
8	
9	    if (user.role === "MANAGER") {
10	      // Manager: tickets from their department pending manager approval
11	      const tickets = await prisma.ticket.findMany({
12	        where: {
13	          applicant: { deptId: user.deptId },
14	          applicantId: { not: user.userId }, // exclude own tickets
15	          status: { in: ["PENDING_MANAGER_1", "PENDING_MANAGER_2"] },
16	          OR: [
17	            { type: { not: "TRANSFER" } },
18	            {
19	              type: "TRANSFER",
20	              status: "PENDING_MANAGER_1",
21	              fromHolder: { deptId: user.deptId },
22	            },
23	          ],
24	        },
25	        orderBy: { createdAt: "desc" },
26	        include: {
27	          applicant: { select: { id: true, name: true, email: true } },
28	          targetAsset: { include: { model: true } },
29	          targetModel: true,
30	        },
31	      });
32	
33	      return Response.json({ tickets });
34	    }
35	
36	    if (user.role === "IT_ADMIN") {
37	      // IT Admin: tickets pending IT action
38	      const tickets = await prisma.ticket.findMany({
39	        where: { status: "PENDING_IT" },
40	        orderBy: { createdAt: "desc" },
41	        include: {
42	          applicant: { select: { id: true, name: true, email: true } },
43	          targetAsset: { include: { model: true } },
44	          targetModel: true,
45	        },
46	      });
47	
48	      return Response.json({ tickets });
49	    }
50	
51	    return Response.json({ error: "No pending approvals for your role" }, { status: 403 });
52	  } catch (e) {
53	    if (e instanceof AuthError) {
54	      return Response.json({ error: e.message }, { status: e.statusCode });
55	    }
56	    return Response.json({ error: "Internal server error" }, { status: 500 });
57	  }
58	}
