1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError } from "@/lib/auth";
4	
5	export async function GET(request: NextRequest) {
6	  try {
7	    const user = await verifyAuth(request);
8	    if (user.role !== "IT_ADMIN") {
9	      return Response.json({ error: "Only IT_ADMIN can access this endpoint" }, { status: 403 });
10	    }
11	
12	    const { searchParams } = new URL(request.url);
13	    const type = searchParams.get("type");
14	    const status = searchParams.get("status");
15	    const page = Math.max(1, parseInt(searchParams.get("page") || "1", 10));
16	    const limit = Math.min(50, Math.max(1, parseInt(searchParams.get("limit") || "20", 10)));
17	    const skip = (page - 1) * limit;
18	
19	    const where: Record<string, unknown> = {};
20	    if (type) where.type = type;
21	    if (status) where.status = status;
22	
23	    const [tickets, total] = await Promise.all([
24	      prisma.ticket.findMany({
25	        where: where as any,
26	        orderBy: { createdAt: "desc" },
27	        skip,
28	        take: limit,
29	        include: {
30	          applicant: { select: { id: true, name: true, email: true } },
31	          targetAsset: { include: { model: true } },
32	          targetModel: true,
33	        },
34	      }),
35	      prisma.ticket.count({ where: where as any }),
36	    ]);
37	
38	    return Response.json({
39	      tickets,
40	      pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
41	    });
42	  } catch (e) {
43	    if (e instanceof AuthError) {
