1	import { NextRequest } from "next/server";
2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError } from "@/lib/auth";
4	import { TicketWorkflow, WorkflowError } from "@/lib/ticket-workflow";
5	import { logTicketStatusChange } from "@/lib/audit";
6	import { notifyApprovalRequest, notifyApprovalResult } from "@/lib/notifications";
7	
8	export async function POST(
9	  request: NextRequest,
10	  { params }: { params: Promise<{ id: string }> }
11	) {
12	  try {
13	    const user = await verifyAuth(request);
14	    const { id } = await params;
15	    const body = await request.json();
16	    const deputy = body.deputy === true;
17	
18	    const result = await prisma.$transaction(async (tx) => {
19	      const ticket = await tx.ticket.findUniqueOrThrow({
20	        where: { id },
21	        include: {
22	          applicant: { include: { department: true } },
23	          targetAsset: true,
24	        },
25	      });
26	
27	      // Ticket must not be in terminal state
28	      if (["COMPLETED", "REJECTED", "CANCELLED"].includes(ticket.status)) {
29	        throw new WorkflowError("Ticket is already in a terminal state");
30	      }
31	
32	      // Determine who can approve
33	      const currentStatus = ticket.status;
34	
35	      if (currentStatus === "PENDING_MANAGER_1" || currentStatus === "PENDING_MANAGER_2") {
36	        if (deputy) {
37	          // Deputy approval: only IT_ADMIN can do this (§8.2.1)
38	          if (user.role !== "IT_ADMIN") {
39	            throw new WorkflowError("Only IT_ADMIN can perform deputy approval");
40	          }
41	        } else {
42	          // Regular manager approval
43	          if (user.role !== "MANAGER" && user.role !== "IT_ADMIN") {
44	            throw new WorkflowError("Only managers can approve");
45	          }
46	          // Manager must be from same department as applicant
47	          if (user.role === "MANAGER") {
48	            if (user.deptId !== ticket.applicant.deptId) {
49	              throw new WorkflowError("You can only approve tickets from your own department");
50	            }
51	            // Manager cannot approve their own tickets (§3.2)
52	            if (user.userId === ticket.applicantId) {
53	              throw new WorkflowError("Cannot approve your own ticket");
54	            }
55	          }
56	        }
57	      } else if (currentStatus === "PENDING_IT") {
58	        // IT approval: only IT_ADMIN
59	        if (user.role !== "IT_ADMIN") {
60	          throw new WorkflowError("Only IT_ADMIN can approve at this stage");
61	        }
62	      } else {
63	        throw new WorkflowError(`Cannot approve ticket in status ${currentStatus}`);
64	      }
65	
66	      const nextStatus = TicketWorkflow.nextOnApprove(ticket.type, currentStatus);
67	      if (!nextStatus) {
68	        throw new WorkflowError("No valid next status for approval");
69	      }
70	
71	      const updateData: Record<string, unknown> = { status: nextStatus };
72	      if (deputy) {
73	        updateData.deputyApproval = true;
74	        updateData.deputyApproverId = user.userId;
75	      }
76	
77	      // If RETURN type and moving to IN_PROGRESS, update asset if needed
78	      if (ticket.type === "RETURN" && nextStatus === "IN_PROGRESS" && ticket.targetAsset) {
79	        // Asset already in RETURNING state from creation
80	      }
81	
82	      const updated = await tx.ticket.update({
83	        where: { id },
84	        data: updateData as any,
85	      });
86	
87	      await logTicketStatusChange(tx, {
88	        ticketId: id,
89	        operatorId: user.userId,
90	        fromStatus: currentStatus,
91	        toStatus: nextStatus,
92	        metadata: {
93	          deputy,
94	          deputyOperatorId: deputy ? user.userId : undefined,
95	        },
96	      });
97	
98	      // Notify applicant about approval
99	      await notifyApprovalResult(tx, {
100	        applicantId: ticket.applicantId,
101	        ticketId: id,
102	        approved: true,
103	        ticketType: ticket.type,
104	      });
105	
106	      // If next is PENDING_IT and there's a manager approval before IT, notify IT
107	      if (nextStatus === "PENDING_IT") {
108	        const itAdmins = await tx.user.findMany({
109	          where: { role: "IT_ADMIN", status: "ACTIVE" },
110	        });
111	        for (const it of itAdmins) {
112	          await notifyApprovalRequest(tx, {
113	            managerId: it.id,
114	            ticketId: id,
115	            applicantName: ticket.applicant.name,
116	            ticketType: ticket.type,
117	          });
118	        }
119	      }
120	
121	      return updated;
122	    });
123	
124	    return Response.json({ ticket: result });
125	  } catch (e) {
126	    if (e instanceof AuthError) {
127	      return Response.json({ error: e.message }, { status: e.statusCode });
128	    }
129	    if (e instanceof WorkflowError) {
130	      return Response.json({ error: e.message }, { status: 400 });
131	    }
132	    return Response.json({ error: "Internal server error" }, { status: 500 });
133	  }
134	}
