40	      if (ticket.targetAsset) {
41	        if (action === "return_holder") {
42	          // Return to original holder
43	          await tx.assetInstance.update({
44	            where: { id: ticket.targetAsset.id },
45	            data: {
46	              status: "IN_USE",
47	              ...(ticket.fromHolderId ? { holderId: ticket.fromHolderId } : {}),
48	            },
49	          });
50	          await logAssetStatusChange(tx, {
51	            assetId: ticket.targetAsset.id,
52	            operatorId: user.userId,
53	            fromStatus: "REPAIRING",
54	            toStatus: "IN_USE",
55	            metadata: { ticketId: id, action: "return_holder" },
56	          });
57	        } else if (action === "make_available") {
58	          await tx.assetInstance.update({
59	            where: { id: ticket.targetAsset.id },
60	            data: { status: "AVAILABLE", holderId: null },
61	          });
62	          await logAssetStatusChange(tx, {
63	            assetId: ticket.targetAsset.id,
64	            operatorId: user.userId,
65	            fromStatus: "REPAIRING",
66	            toStatus: "AVAILABLE",
67	            metadata: { ticketId: id, action: "make_available" },
68	          });
69	        } else if (action === "scrap") {
70	          await tx.assetInstance.update({
71	            where: { id: ticket.targetAsset.id },
72	            data: { status: "SCRAPPED", holderId: null },
73	          });
74	          await logAssetStatusChange(tx, {
75	            assetId: ticket.targetAsset.id,
76	            operatorId: user.userId,
77	            fromStatus: "REPAIRING",
78	            toStatus: "SCRAPPED",
79	            metadata: { ticketId: id, action: "scrap" },
80	          });
81	        }
82	      }
83	
84	      await logTicketStatusChange(tx, {
85	        ticketId: id,
86	        operatorId: user.userId,
87	        fromStatus: "IN_PROGRESS",
88	        toStatus: "COMPLETED",
89	        metadata: { repairAction: action },
90	      });
91	
92	      return updated;
93	    });
94	
95	    return Response.json({ ticket: result });
96	  } catch (e) {
97	    if (e instanceof AuthError) {
98	      return Response.json({ error: e.message }, { status: e.statusCode });
99	    }
100	    if (e instanceof WorkflowError) {
101	      return Response.json({ error: e.message }, { status: 400 });
102	    }
103	    return Response.json({ error: "Internal server error" }, { status: 500 });
104	  }
105	}
