2	import { prisma } from "@/lib/prisma";
3	import { verifyAuth, AuthError } from "@/lib/auth";
4	import { AssetStateMachine, TransitionError } from "@/lib/asset-state-machine";
5	import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";
6	
7	export async function POST(
8	  request: NextRequest,
9	  { params }: { params: Promise<{ id: string }> }
10	) {
11	  try {
12	    const user = await verifyAuth(request);
13	    if (user.role !== "IT_ADMIN") {
14	      return Response.json({ error: "Only IT_ADMIN can mark assets as lost" }, { status: 403 });
15	    }
16	
17	    const { id } = await params;
18	    const body = await request.json();
19	    const reason = body.reason || "";
20	
21	    const result = await prisma.$transaction(async (tx) => {
22	      const { asset, before, after, cancelledTicketIds } =
23	        await AssetStateMachine.transition(tx, id, "LOST" as any, {
24	          operatorId: user.userId,
25	          reason,
26	        });
27	
28	      await logAssetStatusChange(tx, {
29	        assetId: id,
30	        operatorId: user.userId,
31	        fromStatus: before.status,
32	        toStatus: after.status,
33	        metadata: { lostReason: reason, cancelledTickets: cancelledTicketIds },
34	      });
35	
36	      // Log each cancelled ticket (§8.2.2)
37	      for (const ticketId of cancelledTicketIds) {
38	        await logTicketStatusChange(tx, {
39	          ticketId,
40	          operatorId: user.userId,
41	          fromStatus: "ACTIVE",
42	          toStatus: "CANCELLED",
43	          metadata: { reason: "Asset marked as lost" },
44	        });
45	      }
46	
47	      return { asset, cancelledTickets: cancelledTicketIds };
48	    });
49	
50	    return Response.json(result);
51	  } catch (e) {
52	    if (e instanceof AuthError) {
53	      return Response.json({ error: e.message }, { status: e.statusCode });
54	    }
55	    if (e instanceof TransitionError) {
56	      return Response.json({ error: e.message }, { status: 400 });
57	    }
58	    return Response.json({ error: "Internal server error" }, { status: 500 });
59	  }
60	}
