"use client";

/**
 * 审批工作台 (MANAGER + IT_ADMIN)
 * 功能说明: 待审批/已审批工单列表，支持审批和驳回操作
 */

import { useState, useEffect, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import EmptyState from "@/components/empty-state";
import RoleGuard from "@/components/role-guard";
import { apiFetch, ApiError } from "@/lib/api-client";
import { useAuth } from "@/lib/auth-context";
import { CheckCircle, XCircle, Clock, FileText, AlertCircle, RefreshCw } from "lucide-react";
import Link from "next/link";

/* ---------- types ---------- */

type TicketStatus =
  | "SUBMITTED"
  | "PENDING_MANAGER_1"
  | "PENDING_MANAGER_2"
  | "PENDING_IT"
  | "APPROVED"
  | "REJECTED"
  | "IN_PROGRESS"
  | "COMPLETED"
  | "CANCELLED";

type TicketType = "APPLY" | "RETURN" | "REPAIR" | "TRANSFER";

interface TicketItem {
  id: string;
  type: TicketType;
  status: TicketStatus;
  reason?: string;
  rejectReason?: string;
  createdAt: string;
  updatedAt: string;
  applicant?: {
    id: string;
    name: string;
    email: string;
  };
  targetAsset?: {
    id: string;
    sn?: string;
    model?: { brandName: string; modelName: string };
  };
  targetModel?: {
    id: string;
    brandName: string;
    modelName: string;
  };
}

interface Pagination {
  page: number;
  limit: number;
  total: number;
  totalPages: number;
}

/* ---------- labels ---------- */

const statusLabels: Record<string, string> = {
  SUBMITTED: "已提交",
  PENDING_MANAGER_1: "待主管审批",
  PENDING_MANAGER_2: "待主管审批",
  PENDING_IT: "待IT处理",
  APPROVED: "已通过",
  REJECTED: "已驳回",
  IN_PROGRESS: "处理中",
  COMPLETED: "已完成",
  CANCELLED: "已取消",
};

const statusVariants: Record<string, "blue" | "orange" | "green" | "red" | "gray" | "purple"> = {
  SUBMITTED: "blue",
  PENDING_MANAGER_1: "orange",
  PENDING_MANAGER_2: "orange",
  PENDING_IT: "orange",
  APPROVED: "green",
  REJECTED: "red",
  IN_PROGRESS: "purple",
  COMPLETED: "green",
  CANCELLED: "gray",
};

const typeLabels: Record<TicketType, string> = {
  APPLY: "申领",
  RETURN: "归还",
  REPAIR: "报修",
  TRANSFER: "调拨",
};

/* ---------- component ---------- */

export default function ApprovalsPage() {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState<"pending" | "history">("pending");

  // pending
  const [pendingTickets, setPendingTickets] = useState<TicketItem[]>([]);
  const [pendingLoading, setPendingLoading] = useState(true);
  const [pendingError, setPendingError] = useState("");

  // history
  const [historyTickets, setHistoryTickets] = useState<TicketItem[]>([]);
  const [historyLoading, setHistoryLoading] = useState(false);
  const [historyError, setHistoryError] = useState("");
  const [page, setPage] = useState(1);
  const [pagination, setPagination] = useState<Pagination | null>(null);

  // reject dialog
  const [rejectTarget, setRejectTarget] = useState<TicketItem | null>(null);
  const [rejectReason, setRejectReason] = useState("");
  const [rejecting, setRejecting] = useState(false);

  // approving state
  const [approvingIds, setApprovingIds] = useState<Set<string>>(new Set());

  /* ---------- fetch pending ---------- */

  const fetchPending = useCallback(async () => {
    setPendingLoading(true);
    setPendingError("");
    try {
      const data = await apiFetch<{ tickets: TicketItem[] }>("/api/approvals/pending");
      setPendingTickets(data.tickets || []);
    } catch (e) {
      setPendingError(e instanceof ApiError ? e.message : "加载待审批列表失败");
    } finally {
      setPendingLoading(false);
    }
  }, []);

  useEffect(() => {
    if (activeTab === "pending") fetchPending();
  }, [activeTab, fetchPending]);

  /* ---------- fetch history ---------- */

  const fetchHistory = useCallback(async (p: number) => {
    setHistoryLoading(true);
    setHistoryError("");
    try {
      const data = await apiFetch<{ tickets: TicketItem[]; pagination: Pagination }>(
        `/api/approvals/history?page=${p}&limit=20`
      );
      setHistoryTickets(data.tickets || []);
      setPagination(data.pagination || null);
    } catch (e) {
      setHistoryError(e instanceof ApiError ? e.message : "加载审批历史失败");
    } finally {
      setHistoryLoading(false);
    }
  }, []);

  useEffect(() => {
    if (activeTab === "history") fetchHistory(page);
  }, [activeTab, page, fetchHistory]);

  /* ---------- approve ---------- */

  const handleApprove = async (ticket: TicketItem) => {
    setApprovingIds((prev) => new Set(prev).add(ticket.id));
    try {
      const body: Record<string, unknown> = {};
      // IT_ADMIN approving manager-stage = deputy approval
      if (
        user.role === "IT_ADMIN" &&
        (ticket.status === "PENDING_MANAGER_1" || ticket.status === "PENDING_MANAGER_2")
      ) {
        body.deputy = true;
      }
      await apiFetch(`/api/tickets/${ticket.id}/approve`, {
        method: "POST",
        body: JSON.stringify(body),
      });
      // refresh
      await fetchPending();
    } catch (e) {
      alert(e instanceof ApiError ? e.message : "审批失败");
    } finally {
      setApprovingIds((prev) => {
        const next = new Set(prev);
        next.delete(ticket.id);
        return next;
      });
    }
  };

  /* ---------- reject ---------- */

  const handleReject = async () => {
    if (!rejectTarget) return;
    setRejecting(true);
    try {
      await apiFetch(`/api/tickets/${rejectTarget.id}/reject`, {
        method: "POST",
        body: JSON.stringify({ reason: rejectReason || undefined }),
      });
      setRejectTarget(null);
      setRejectReason("");
      await fetchPending();
    } catch (e) {
      alert(e instanceof ApiError ? e.message : "驳回失败");
    } finally {
      setRejecting(false);
    }
  };

  /* ---------- asset label ---------- */

  const assetLabel = (t: TicketItem) => {
    if (t.targetAsset?.model) {
      return `${t.targetAsset.model.brandName} ${t.targetAsset.model.modelName}`;
    }
    if (t.targetModel) {
      return `${t.targetModel.brandName} ${t.targetModel.modelName}`;
    }
    return "—";
  };

  /* ---------- render ---------- */

  return (
    <RoleGuard roles={["MANAGER", "IT_ADMIN"]}>
      <div className="max-w-4xl mx-auto space-y-6">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">审批工作台</h1>
          <p className="text-muted-foreground mt-1">
            {user.role === "IT_ADMIN" ? "IT 代审批与工单管理" : "管理部门员工的工单申请"}
          </p>
        </div>

        {/* Tabs */}
        <div className="flex gap-2 border-b pb-1">
          {([
            { key: "pending", label: "待审批" },
            { key: "history", label: "已审批" },
          ] as const).map((tab) => (
            <button
              key={tab.key}
              onClick={() => {
                setActiveTab(tab.key);
                setPage(1);
              }}
              className={`px-4 py-2 text-sm font-medium rounded-t-lg transition-colors ${
                activeTab === tab.key
                  ? "bg-background border border-b-background text-foreground -mb-px"
                  : "text-muted-foreground hover:text-foreground"
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* ---- Pending Tab ---- */}
        {activeTab === "pending" && (
          <>
            {pendingLoading ? (
              <div className="space-y-3">
                {Array.from({ length: 3 }).map((_, i) => (
                  <Skeleton key={i} className="h-28 rounded-xl" />
                ))}
              </div>
            ) : pendingError ? (
              <Card>
                <CardContent className="flex items-center justify-center gap-2 py-12 text-destructive">
                  <AlertCircle className="w-5 h-5" />
                  <span>{pendingError}</span>
                  <Button variant="outline" size="sm" onClick={fetchPending}>
                    <RefreshCw className="w-4 h-4 mr-1" />重试
                  </Button>
                </CardContent>
              </Card>
            ) : pendingTickets.length === 0 ? (
              <EmptyState
                icon={CheckCircle}
                title="暂无待审批工单"
                description="目前没有需要你审批的工单"
              />
            ) : (
              <div className="space-y-3">
                {pendingTickets.map((ticket) => (
                  <Card key={ticket.id} className="hover:shadow-sm transition-shadow">
                    <CardContent className="p-4">
                      <div className="flex items-start justify-between gap-4">
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            <Link
                              href={`/tickets/${ticket.id}`}
                              className="font-medium hover:text-primary transition-colors"
                            >
                              {ticket.id}
                            </Link>
                            <Badge variant={typeLabels[ticket.type] ? "blue" : "gray"}>
                              {typeLabels[ticket.type] || ticket.type}
                            </Badge>
                            <Badge variant={statusVariants[ticket.status] || "gray"}>
                              {statusLabels[ticket.status] || ticket.status}
                            </Badge>
                          </div>
                          <div className="mt-2 text-sm text-muted-foreground space-y-0.5">
                            <p>
                              资产: {assetLabel(ticket)}
                            </p>
                            <p>
                              申请人: {ticket.applicant?.name || "—"}
                              {ticket.applicant?.email ? ` (${ticket.applicant.email})` : ""}
                            </p>
                            <p>申请时间: {new Date(ticket.createdAt).toLocaleString("zh-CN")}</p>
                          </div>
                        </div>
                        <div className="flex items-center gap-2 shrink-0">
                          <Button
                            size="sm"
                            onClick={() => handleApprove(ticket)}
                            disabled={approvingIds.has(ticket.id)}
                          >
                            <CheckCircle className="w-4 h-4 mr-1" />
                            {approvingIds.has(ticket.id) ? "处理中..." : "通过"}
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => setRejectTarget(ticket)}
                            disabled={approvingIds.has(ticket.id)}
                          >
                            <XCircle className="w-4 h-4 mr-1" />
                            驳回
                          </Button>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </>
        )}

        {/* ---- History Tab ---- */}
        {activeTab === "history" && (
          <>
            {historyLoading ? (
              <div className="space-y-3">
                {Array.from({ length: 3 }).map((_, i) => (
                  <Skeleton key={i} className="h-24 rounded-xl" />
                ))}
              </div>
            ) : historyError ? (
              <Card>
                <CardContent className="flex items-center justify-center gap-2 py-12 text-destructive">
                  <AlertCircle className="w-5 h-5" />
                  <span>{historyError}</span>
                  <Button variant="outline" size="sm" onClick={() => fetchHistory(page)}>
                    <RefreshCw className="w-4 h-4 mr-1" />重试
                  </Button>
                </CardContent>
              </Card>
            ) : historyTickets.length === 0 ? (
              <EmptyState
                icon={Clock}
                title="暂无审批记录"
                description="你还没有处理过任何审批"
              />
            ) : (
              <div className="space-y-3">
                {historyTickets.map((ticket) => (
                  <Link key={ticket.id} href={`/tickets/${ticket.id}`}>
                    <Card className="hover:shadow-sm transition-shadow cursor-pointer">
                      <CardContent className="p-4 flex items-center justify-between">
                        <div className="flex items-center gap-4">
                          <div className="w-10 h-10 rounded-lg bg-muted flex items-center justify-center shrink-0">
                            <FileText className="w-5 h-5 text-muted-foreground" />
                          </div>
                          <div>
                            <p className="font-medium text-sm">
                              {typeLabels[ticket.type] || ticket.type} - {assetLabel(ticket)}
                            </p>
                            <div className="flex items-center gap-2 mt-0.5">
                              <span className="text-xs text-muted-foreground">{ticket.id}</span>
                              <Badge variant={statusVariants[ticket.status] || "gray"}>
                                {statusLabels[ticket.status] || ticket.status}
                              </Badge>
                              <span className="text-xs text-muted-foreground">
                                {ticket.applicant?.name || "—"}
                              </span>
                            </div>
                          </div>
                        </div>
                        <span className="text-xs text-muted-foreground shrink-0">
                          {new Date(ticket.updatedAt).toLocaleDateString("zh-CN")}
                        </span>
                      </CardContent>
                    </Card>
                  </Link>
                ))}

                {/* Pagination */}
                {pagination && pagination.totalPages > 1 && (
                  <div className="flex items-center justify-center gap-2 pt-2">
                    <Button
                      variant="outline"
                      size="sm"
                      disabled={page <= 1}
                      onClick={() => setPage((p) => Math.max(1, p - 1))}
                    >
                      上一页
                    </Button>
                    <span className="text-sm text-muted-foreground">
                      {page} / {pagination.totalPages}
                    </span>
                    <Button
                      variant="outline"
                      size="sm"
                      disabled={page >= pagination.totalPages}
                      onClick={() => setPage((p) => p + 1)}
                    >
                      下一页
                    </Button>
                  </div>
                )}
              </div>
            )}
          </>
        )}

        {/* Reject Dialog */}
        <Dialog open={!!rejectTarget} onOpenChange={(open) => !open && setRejectTarget(null)}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>驳回工单</DialogTitle>
              <DialogDescription>
                确认驳回工单 {rejectTarget?.id}？请填写驳回理由。
              </DialogDescription>
            </DialogHeader>
            <Textarea
              placeholder="驳回理由（选填）"
              value={rejectReason}
              onChange={(e) => setRejectReason(e.target.value)}
              rows={3}
            />
            <DialogFooter>
              <Button variant="outline" onClick={() => setRejectTarget(null)}>
                取消
              </Button>
              <Button variant="destructive" onClick={handleReject} disabled={rejecting}>
                {rejecting ? "驳回中..." : "确认驳回"}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </RoleGuard>
  );
}

