      const ticketsData = await apiFetch<{ tickets: unknown[] }>(
        "/api/it/tickets?status=PENDING_IT&limit=10"
      );
      const pendingCount = (ticketsData.tickets || []).length;

      // Fetch assets to get counts
      let inStockCount = 0;
      let totalCount = 0;
      try {
        const assetsData = await apiFetch<{ assets: unknown[]; pagination: { total: number } }>(
          "/api/it/assets?limit=1"
        );
        totalCount = assetsData.pagination?.total ?? 0;
      } catch {
        // assets endpoint may fail silently
      }
      try {
        const inStockData = await apiFetch<{ assets: unknown[]; pagination: { total: number } }>(
          "/api/it/assets?status=IN_STOCK&limit=1"
        );
        inStockCount = inStockData.pagination?.total ?? 0;
      } catch {
        // fallback
      }

      setStats({
        pendingTickets: pendingCount,
        inStockAssets: inStockCount,
        totalAssets: totalCount,
      });
