};

const typeLabels: Record<TicketType, string> = {
  APPLY: "申领",
  RETURN: "归还",
  REPAIR: "报修",
  TRANSFER: "调拨",
};

/* ---------- component ---------- */

export default function ITTicketsPage() {
  const [tickets, setTickets] = useState<TicketItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  // filters
  const [typeFilter, setTypeFilter] = useState<string>("");
  const [statusFilter, setStatusFilter] = useState<string>("");

  // pagination
  const [page, setPage] = useState(1);
  const [pagination, setPagination] = useState<Pagination | null>(null);

  // actions
  const [actingIds, setActingIds] = useState<Set<string>>(new Set());
  const [assignDialogOpen, setAssignDialogOpen] = useState(false);
  const [assignTarget, setAssignTarget] = useState<TicketItem | null>(null);
  const [assetIdInput, setAssetIdInput] = useState("");

  /* ---------- fetch ---------- */

  const fetchTickets = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const params = new URLSearchParams();
      params.set("page", String(page));
      params.set("limit", "20");
      if (typeFilter) params.set("type", typeFilter);
      if (statusFilter) params.set("status", statusFilter);

      const data = await apiFetch<{ tickets: TicketItem[]; pagination: Pagination }>(
        `/api/it/tickets?${params.toString()}`
      );
      setTickets(data.tickets || []);
      setPagination(data.pagination || null);
    } catch (e) {
      setError(e instanceof ApiError ? e.message : "加载工单列表失败");
    } finally {
      setLoading(false);
    }
  }, [page, typeFilter, statusFilter]);

  useEffect(() => {
    fetchTickets();
  }, [fetchTickets]);

  /* ---------- assign ---------- */

  const handleAssign = async () => {
    if (!assignTarget || !assetIdInput.trim()) return;
    setActingIds((prev) => new Set(prev).add(assignTarget.id));
    try {
      await apiFetch(`/api/tickets/${assignTarget.id}/assign`, {
        method: "POST",
        body: JSON.stringify({ assetId: assetIdInput.trim() }),
      });
      setAssignDialogOpen(false);
      setAssignTarget(null);
      setAssetIdInput("");
      await fetchTickets();
    } catch (e) {
      alert(e instanceof ApiError ? e.message : "分配失败");
    } finally {
      setActingIds((prev) => {
        const next = new Set(prev);
        next.delete(assignTarget.id);
        return next;
      });
    }
  };

  /* ---------- accept (REPAIR) ---------- */

  const handleAccept = async (ticket: TicketItem) => {
    setActingIds((prev) => new Set(prev).add(ticket.id));
    try {
      await apiFetch(`/api/tickets/${ticket.id}/accept`, { method: "POST" });
      await fetchTickets();
    } catch (e) {
      alert(e instanceof ApiError ? e.message : "接单失败");
    } finally {
      setActingIds((prev) => {
        const next = new Set(prev);
        next.delete(ticket.id);
        return next;
      });
    }
  };

  /* ---------- complete ---------- */

  const handleComplete = async (ticket: TicketItem) => {
    setActingIds((prev) => new Set(prev).add(ticket.id));
    try {
      await apiFetch(`/api/tickets/${ticket.id}/complete`, {
        method: "POST",
        body: JSON.stringify({ action: "return_holder" }),
      });
      await fetchTickets();
    } catch (e) {
      alert(e instanceof ApiError ? e.message : "完成失败");
    } finally {
      setActingIds((prev) => {
        const next = new Set(prev);
        next.delete(ticket.id);
        return next;
      });
    }
  };

  /* ---------- helpers ---------- */

  const assetLabel = (t: TicketItem) => {
    if (t.targetAsset?.model) {
      return `${t.targetAsset.model.brandName} ${t.targetAsset.model.modelName}`;
    }
    if (t.targetModel) {
      return `${t.targetModel.brandName} ${t.targetModel.modelName}`;
    }
    return "—";
  };

  /* ---------- render ---------- */

  return (
    <RoleGuard roles={["IT_ADMIN"]}>
      <div className="max-w-6xl mx-auto space-y-6">
        <div className="flex items-center justify-between flex-wrap gap-2">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">IT 工单工作台</h1>
            <p className="text-muted-foreground mt-1">管理所有资产流转工单</p>
          </div>
          <Button variant="outline" size="sm" onClick={fetchTickets} disabled={loading}>
            <RefreshCw className={`w-4 h-4 mr-1 ${loading ? "animate-spin" : ""}`} />
            刷新
          </Button>
        </div>

        {/* Filters */}
        <Card>
          <CardContent className="p-4">
            <div className="flex flex-wrap gap-3 items-center">
              <Filter className="w-4 h-4 text-muted-foreground" />
              <select
                value={typeFilter}
                onChange={(e) => { setTypeFilter(e.target.value); setPage(1); }}
                className="text-sm border rounded-md px-3 py-1.5 bg-background"
              >
                <option value="">全部类型</option>
                <option value="APPLY">申领</option>
                <option value="RETURN">归还</option>
                <option value="REPAIR">报修</option>
                <option value="TRANSFER">调拨</option>
              </select>
              <select
                value={statusFilter}
                onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
                className="text-sm border rounded-md px-3 py-1.5 bg-background"
              >
                <option value="">全部状态</option>
                <option value="PENDING_IT">待IT处理</option>
                <option value="APPROVED">已通过</option>
                <option value="IN_PROGRESS">处理中</option>
                <option value="COMPLETED">已完成</option>
                <option value="REJECTED">已驳回</option>
                <option value="CANCELLED">已取消</option>
              </select>
            </div>
          </CardContent>
        </Card>

        {/* Ticket List */}
        {loading ? (
          <div className="space-y-3">
            {Array.from({ length: 5 }).map((_, i) => (
              <Skeleton key={i} className="h-20 rounded-xl" />
            ))}
          </div>
        ) : error ? (
          <Card>
            <CardContent className="flex items-center justify-center gap-2 py-12 text-destructive">
              <AlertCircle className="w-5 h-5" />
              <span>{error}</span>
              <Button variant="outline" size="sm" onClick={fetchTickets}>
                <RefreshCw className="w-4 h-4 mr-1" />重试
              </Button>
            </CardContent>
          </Card>
        ) : tickets.length === 0 ? (
          <EmptyState
            icon={Ticket}
            title="暂无工单"
            description="没有匹配筛选条件的工单"
          />
        ) : (
          <div className="space-y-3">
            {tickets.map((ticket) => (
              <Card key={ticket.id} className="hover:shadow-sm transition-shadow">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between gap-4 flex-wrap">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <Link
                          href={`/tickets/${ticket.id}`}
                          className="font-medium text-sm hover:text-primary transition-colors"
                        >
                          {ticket.id}
                        </Link>
                        <Badge variant={typeLabels[ticket.type] ? "blue" : "gray"}>
                          {typeLabels[ticket.type] || ticket.type}
                        </Badge>
                        <Badge variant={statusVariants[ticket.status] || "gray"}>
                          {statusLabels[ticket.status] || ticket.status}
                        </Badge>
                      </div>
                      <div className="mt-1.5 text-sm text-muted-foreground flex flex-wrap gap-x-4 gap-y-0.5">
                        <span>资产: {assetLabel(ticket)}</span>
                        <span>申请人: {ticket.applicant?.name || "—"}</span>
                        <span>{new Date(ticket.createdAt).toLocaleString("zh-CN")}</span>
                      </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex items-center gap-2 shrink-0">
                      {ticket.status === "APPROVED" && ticket.type === "APPLY" && (
                        <Button
                          size="sm"
                          onClick={() => { setAssignTarget(ticket); setAssignDialogOpen(true); }}
                          disabled={actingIds.has(ticket.id)}
                        >
                          <UserPlus className="w-4 h-4 mr-1" />
                          分配资产
                        </Button>
                      )}
                      {ticket.status === "PENDING_IT" && ticket.type === "REPAIR" && (
                        <Button
                          size="sm"
                          onClick={() => handleAccept(ticket)}
                          disabled={actingIds.has(ticket.id)}
                        >
                          <ClipboardCheck className="w-4 h-4 mr-1" />
                          接单
                        </Button>
                      )}
                      {ticket.status === "IN_PROGRESS" && ticket.type === "REPAIR" && (
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => handleComplete(ticket)}
                          disabled={actingIds.has(ticket.id)}
                        >
                          <CheckCircle2 className="w-4 h-4 mr-1" />
                          完成
                        </Button>
                      )}
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}

            {/* Pagination */}
            {pagination && pagination.totalPages > 1 && (
              <div className="flex items-center justify-center gap-2 pt-2">
                <Button
                  variant="outline"
                  size="sm"
                  disabled={page <= 1}
                  onClick={() => setPage((p) => Math.max(1, p - 1))}
                >
                  上一页
                </Button>
                <span className="text-sm text-muted-foreground">
                  {page} / {pagination.totalPages} (共 {pagination.total} 条)
                </span>
                <Button
                  variant="outline"
                  size="sm"
                  disabled={page >= pagination.totalPages}
                  onClick={() => setPage((p) => p + 1)}
                >
                  下一页
                </Button>
              </div>
            )}
          </div>
        )}

        {/* Assign Dialog */}
        <Dialog open={assignDialogOpen} onOpenChange={setAssignDialogOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>分配资产</DialogTitle>
              <DialogDescription>
                为工单 {assignTarget?.id} 分配一个具体资产实例
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-2">
              <label className="text-sm font-medium">资产 ID</label>
              <Input
                placeholder="输入资产 ID（如 AST-001）"
                value={assetIdInput}
                onChange={(e) => setAssetIdInput(e.target.value)}
              />
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setAssignDialogOpen(false)}>
                取消
              </Button>
              <Button onClick={handleAssign} disabled={!assetIdInput.trim() || actingIds.has(assignTarget?.id || "")}>
                确认分配
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </RoleGuard>
  );
}

