/* ---------- component ---------- */

export default function ITAssetDetailPage() {
  const params = useParams();
  const router = useRouter();
  const assetId = params.id as string;

  const [asset, setAsset] = useState<AssetDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [timeline, setTimeline] = useState<TimelineEvent[]>([]);
  const [timelineLoading, setTimelineLoading] = useState(true);

  // scrap dialog
  const [scrapOpen, setScrapOpen] = useState(false);
  const [scrapReason, setScrapReason] = useState("");
  const [scrapping, setScrapping] = useState(false);

  // lost dialog
  const [lostOpen, setLostOpen] = useState(false);
  const [lostReason, setLostReason] = useState("");
  const [losting, setLosting] = useState(false);

  /* ---------- fetch asset ---------- */

  const fetchAsset = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const data = await apiFetch<{ asset: AssetDetail }>(`/api/it/assets/${assetId}`);
      setAsset(data.asset);
    } catch (e) {
      setError(e instanceof ApiError ? e.message : "加载资产详情失败");
    } finally {
      setLoading(false);
    }
  }, [assetId]);

  useEffect(() => {
    fetchAsset();
  }, [fetchAsset]);

  /* ---------- fetch timeline ---------- */

  const fetchTimeline = useCallback(async () => {
    setTimelineLoading(true);
    try {
      const data = await apiFetch<{ timeline: AuditLogItem[] }>(
        `/api/it/assets/${assetId}/timeline`
      );
      const events: TimelineEvent[] = (data.timeline || []).map((log, i, arr) => ({
        id: log.id,
        status: i === arr.length - 1 ? "current" : "completed",
        title: log.action || "状态变更",
        description: log.fromStatus && log.toStatus
          ? `${log.fromStatus} -> ${log.toStatus}`
          : undefined,
        timestamp: log.createdAt
          ? new Date(log.createdAt).toLocaleString("zh-CN")
          : undefined,
        actor: log.operator?.name,
      }));
      // If no audit logs, create initial entry
      if (events.length === 0 && asset) {
        events.push({
          id: "init",
          status: "current",
          title: "资产创建",
          description: `状态: ${asset.status}`,
          timestamp: asset.createdAt
            ? new Date(asset.createdAt).toLocaleString("zh-CN")
            : undefined,
        });
      }
      setTimeline(events);
    } catch {
      // Timeline is supplementary; don't block the page
      if (asset) {
        setTimeline([
          {
            id: "init",
            status: "current",
            title: "资产创建",
            description: `状态: ${asset.status}`,
            timestamp: asset.createdAt
              ? new Date(asset.createdAt).toLocaleString("zh-CN")
              : undefined,
          },
        ]);
      }
    } finally {
      setTimelineLoading(false);
    }
  }, [assetId, asset]);

  useEffect(() => {
    if (asset) fetchTimeline();
  }, [asset, fetchTimeline]);

  /* ---------- scrap ---------- */

  const handleScrap = async () => {
    setScrapping(true);
    try {
      await apiFetch(`/api/it/assets/${assetId}/scrap`, {
        method: "POST",
        body: JSON.stringify({ reason: scrapReason || undefined }),
      });
      setScrapOpen(false);
      setScrapReason("");
      await fetchAsset();
      await fetchTimeline();
    } catch (e) {
      alert(e instanceof ApiError ? e.message : "报废操作失败");
    } finally {
      setScrapping(false);
    }
  };

  /* ---------- lost ---------- */

  const handleLost = async () => {
    setLosting(true);
    try {
      await apiFetch(`/api/it/assets/${assetId}/lost`, {
        method: "POST",
        body: JSON.stringify({ reason: lostReason || undefined }),
      });
      setLostOpen(false);
      setLostReason("");
      await fetchAsset();
      await fetchTimeline();
    } catch (e) {
      alert(e instanceof ApiError ? e.message : "标记丢失失败");
    } finally {
      setLosting(false);
    }
  };

  /* ---------- helpers ---------- */

  const typeLabels: Record<string, string> = {
    APPLY: "申领",
    RETURN: "归还",
    REPAIR: "报修",
    TRANSFER: "调拨",
  };

  /* ---------- render ---------- */

  if (loading) {
    return (
      <RoleGuard roles={["IT_ADMIN"]}>
        <div className="max-w-4xl mx-auto space-y-6">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-64 rounded-xl" />
          <Skeleton className="h-48 rounded-xl" />
        </div>
      </RoleGuard>
    );
  }

  if (error || !asset) {
    return (
      <RoleGuard roles={["IT_ADMIN"]}>
        <div className="max-w-4xl mx-auto">
          <Card>
            <CardContent className="flex flex-col items-center gap-3 py-12">
              <AlertCircle className="w-8 h-8 text-destructive" />
              <p className="text-destructive">{error || "资产不存在"}</p>
              <div className="flex gap-2">
                <Button variant="outline" onClick={() => router.back()}>
                  <ArrowLeft className="w-4 h-4 mr-1" />返回
                </Button>
                <Button variant="outline" onClick={fetchAsset}>
                  <RefreshCw className="w-4 h-4 mr-1" />重试
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      </RoleGuard>
    );
  }

  return (
    <RoleGuard roles={["IT_ADMIN"]}>
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between flex-wrap gap-2">
          <div className="flex items-center gap-3">
            <Button variant="ghost" size="sm" onClick={() => router.back()}>
              <ArrowLeft className="w-4 h-4 mr-1" />返回
            </Button>
            <div>
              <h1 className="text-2xl font-bold tracking-tight">
                {asset.model
                  ? `${asset.model.brandName} ${asset.model.modelName}`
                  : asset.id}
              </h1>
              <p className="text-muted-foreground text-sm mt-0.5">资产编号: {asset.id}</p>
            </div>
          </div>
          <AssetStatusBadge status={asset.status} />
        </div>

        {/* Info Card */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <Package className="w-5 h-5 text-muted-foreground" />
              资产信息
            </CardTitle>
          </CardHeader>
          <CardContent>
            <dl className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm">
              <div>
                <dt className="text-muted-foreground">资产编号</dt>
                <dd className="font-medium">{asset.id}</dd>
              </div>
              {asset.sn && (
                <div>
                  <dt className="text-muted-foreground">序列号 (SN)</dt>
                  <dd className="font-medium font-mono">{asset.sn}</dd>
                </div>
              )}
              {asset.model && (
                <>
                  <div>
                    <dt className="text-muted-foreground">品牌 / 型号</dt>
                    <dd className="font-medium">{asset.model.brandName} {asset.model.modelName}</dd>
                  </div>
                  <div>
                    <dt className="text-muted-foreground">分类</dt>
                    <dd className="font-medium">{asset.model.category || "—"}</dd>
                  </div>
                  {asset.model.specs && (
                    <div className="sm:col-span-2">
                      <dt className="text-muted-foreground">规格参数</dt>
                      <dd className="font-medium">{asset.model.specs}</dd>
                    </div>
                  )}
                  {asset.model.purchasePrice !== undefined && (
                    <div>
                      <dt className="text-muted-foreground">采购价格</dt>
                      <dd className="font-medium">¥{asset.model.purchasePrice.toLocaleString()}</dd>
                    </div>
                  )}
                  {asset.model.supplier && (
                    <div>
                      <dt className="text-muted-foreground">供应商</dt>
                      <dd className="font-medium">{asset.model.supplier}</dd>
                    </div>
                  )}
                </>
              )}
              <div>
                <dt className="text-muted-foreground">状态</dt>
                <dd><AssetStatusBadge status={asset.status} /></dd>
              </div>
              {asset.purchaseDate && (
                <div>
                  <dt className="text-muted-foreground">采购日期</dt>
                  <dd className="font-medium">
                    {new Date(asset.purchaseDate).toLocaleDateString("zh-CN")}
                  </dd>
                </div>
              )}
              {asset.warrantyExpiry && (
                <div>
                  <dt className="text-muted-foreground">保修到期</dt>
                  <dd className="font-medium">
                    {new Date(asset.warrantyExpiry).toLocaleDateString("zh-CN")}
                  </dd>
                </div>
              )}
            </dl>
          </CardContent>
        </Card>

        {/* Holder & Department */}
        {(asset.holder || asset.department) && (
          <Card>
            <CardHeader>
              <CardTitle className="text-base flex items-center gap-2">
                <User className="w-5 h-5 text-muted-foreground" />
                归属信息
              </CardTitle>
            </CardHeader>
            <CardContent>
              <dl className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm">
                {asset.holder && (
                  <div>
                    <dt className="text-muted-foreground">当前持有人</dt>
                    <dd className="font-medium">{asset.holder.name}</dd>
                  </div>
                )}
                {asset.department && (
                  <div>
                    <dt className="text-muted-foreground">所属部门</dt>
                    <dd className="font-medium">{asset.department.name}</dd>
                  </div>
                )}
              </dl>
            </CardContent>
          </Card>
        )}

        {/* Actions */}
        <div className="flex gap-3 justify-end">
          <Button
            variant="outline"
            onClick={() => setLostOpen(true)}
            disabled={asset.status === "LOST" || asset.status === "SCRAPPED"}
          >
            <AlertTriangle className="w-4 h-4 mr-1" />
            标记丢失
          </Button>
          <Button
            variant="destructive"
            onClick={() => setScrapOpen(true)}
            disabled={asset.status === "SCRAPPED"}
          >
            <Trash2 className="w-4 h-4 mr-1" />
            报废
          </Button>
        </div>

        {/* Timeline */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">生命周期</CardTitle>
          </CardHeader>
          <CardContent>
            {timelineLoading ? (
              <div className="space-y-3">
                {Array.from({ length: 3 }).map((_, i) => (
                  <Skeleton key={i} className="h-12 rounded" />
                ))}
              </div>
            ) : (
              <TicketTimeline events={timeline} />
            )}
          </CardContent>
        </Card>

        {/* Related Tickets */}
        {asset.tickets && asset.tickets.length > 0 && (
          <Card>
            <CardHeader>
              <CardTitle className="text-base flex items-center gap-2">
                <FileText className="w-5 h-5 text-muted-foreground" />
                关联工单
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              {asset.tickets.map((ticket) => (
                <Link
                  key={ticket.id}
                  href={`/tickets/${ticket.id}`}
                  className="flex items-center justify-between p-3 rounded-lg hover:bg-muted transition-colors"
