                  <div className="flex items-center gap-3">
                    <FileText className="w-4 h-4 text-muted-foreground" />
                    <div>
                      <p className="text-sm font-medium">{ticket.id}</p>
                      <p className="text-xs text-muted-foreground">
                        {typeLabels[ticket.type] || ticket.type}
                        {ticket.applicant && ` - ${ticket.applicant.name}`}
                      </p>
                    </div>
                  </div>
                  <span className="text-xs text-muted-foreground">
                    {new Date(ticket.createdAt).toLocaleDateString("zh-CN")}
                  </span>
                </Link>
              ))}
            </CardContent>
          </Card>
        )}

        {/* Scrap Dialog */}
        <Dialog open={scrapOpen} onOpenChange={setScrapOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>报废资产</DialogTitle>
              <DialogDescription>
                确认报废资产 {asset.id}？此操作不可逆。
              </DialogDescription>
            </DialogHeader>
            <Textarea
              placeholder="报废原因（选填）"
              value={scrapReason}
              onChange={(e) => setScrapReason(e.target.value)}
              rows={3}
            />
            <DialogFooter>
              <Button variant="outline" onClick={() => setScrapOpen(false)}>
                取消
              </Button>
              <Button variant="destructive" onClick={handleScrap} disabled={scrapping}>
                {scrapping ? "处理中..." : "确认报废"}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        {/* Lost Dialog */}
        <Dialog open={lostOpen} onOpenChange={setLostOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>标记丢失</DialogTitle>
              <DialogDescription>
                将资产 {asset.id} 标记为丢失状态。关联的活跃工单将被自动取消。
              </DialogDescription>
            </DialogHeader>
            <Textarea
              placeholder="丢失原因（选填）"
              value={lostReason}
              onChange={(e) => setLostReason(e.target.value)}
              rows={3}
            />
            <DialogFooter>
              <Button variant="outline" onClick={() => setLostOpen(false)}>
                取消
              </Button>
              <Button variant="destructive" onClick={handleLost} disabled={losting}>
                {losting ? "处理中..." : "确认标记丢失"}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </RoleGuard>
  );
}

"use client";

/**
 * 资产入库 (IT_ADMIN)
 * 功能说明: 新购设备入库表单，POST /api/it/assets/inbound
 */

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import RoleGuard from "@/components/role-guard";
import { apiFetch, ApiError } from "@/lib/api-client";
import {
  Box,
  CheckCircle2,
  AlertCircle,
  PackagePlus,
} from "lucide-react";

/* ---------- component ---------- */

export default function ITInboundPage() {
  const [assetId, setAssetId] = useState("");
  const [sn, setSn] = useState("");
  const [modelId, setModelId] = useState("");
  const [purchaseDate, setPurchaseDate] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!assetId.trim() || !sn.trim() || !modelId.trim() || !purchaseDate) {
      setError("请填写所有必填字段");
      return;
    }

    setSubmitting(true);
    setError("");
    setSuccess(false);

    try {
      await apiFetch("/api/it/assets/inbound", {
        method: "POST",
        body: JSON.stringify({
          id: assetId.trim(),
          sn: sn.trim(),
          modelId: modelId.trim(),
          purchaseDate,
        }),
      });
      setSuccess(true);
      // Reset form
      setAssetId("");
      setSn("");
      setModelId("");
      setPurchaseDate("");
    } catch (e) {
      setError(e instanceof ApiError ? e.message : "入库失败");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <RoleGuard roles={["IT_ADMIN"]}>
      <div className="max-w-lg mx-auto space-y-6">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">资产入库</h1>
          <p className="text-muted-foreground mt-1">新购设备扫码入库，录入资产信息</p>
        </div>

        {success && (
          <Card className="border-green-200 bg-green-50">
            <CardContent className="flex items-center gap-2 py-4 text-green-800">
              <CheckCircle2 className="w-5 h-5" />
              <span className="text-sm font-medium">资产入库成功！可以继续添加入库。</span>
            </CardContent>
          </Card>
        )}

        {error && (
          <Card className="border-red-200 bg-red-50">
            <CardContent className="flex items-center gap-2 py-4 text-red-800">
              <AlertCircle className="w-5 h-5" />
              <span className="text-sm font-medium">{error}</span>
            </CardContent>
          </Card>
        )}

        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <PackagePlus className="w-5 h-5 text-muted-foreground" />
              入库信息
            </CardTitle>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="text-sm font-medium mb-1.5 block">
                  资产 ID <span className="text-destructive">*</span>
                </label>
                <Input
                  placeholder="例如: AST-2026-001"
                  value={assetId}
                  onChange={(e) => setAssetId(e.target.value)}
                  disabled={submitting}
                />
                <p className="text-xs text-muted-foreground mt-1">资产的唯一标识编号</p>
              </div>

              <div>
                <label className="text-sm font-medium mb-1.5 block">
                  序列号 (SN) <span className="text-destructive">*</span>
                </label>
                <Input
                  placeholder="例如: SN-PF4X8J2K"
                  value={sn}
                  onChange={(e) => setSn(e.target.value)}
                  disabled={submitting}
                />
                <p className="text-xs text-muted-foreground mt-1">设备机身序列号，全局唯一</p>
              </div>

              <div>
                <label className="text-sm font-medium mb-1.5 block">
                  型号 ID <span className="text-destructive">*</span>
                </label>
                <Input
                  placeholder="例如: MODEL-THINKPAD-X1-G12"
                  value={modelId}
                  onChange={(e) => setModelId(e.target.value)}
                  disabled={submitting}
                />
                <p className="text-xs text-muted-foreground mt-1">
                  对应的设备型号 ID（需先在型号管理中创建）
                </p>
              </div>

              <div>
                <label className="text-sm font-medium mb-1.5 block">
                  采购日期 <span className="text-destructive">*</span>
                </label>
                <Input
                  type="date"
                  value={purchaseDate}
                  onChange={(e) => setPurchaseDate(e.target.value)}
                  disabled={submitting}
                />
                <p className="text-xs text-muted-foreground mt-1">
                  用于自动计算保修截止日期
                </p>
              </div>

              <Button type="submit" className="w-full" disabled={submitting}>
                <Box className="w-4 h-4 mr-2" />
                {submitting ? "入库中..." : "确认入库"}
              </Button>
            </form>
          </CardContent>
        </Card>
      </div>
    </RoleGuard>
  );
}

