                    <p className="font-semibold">{model.brandName} {model.modelName}</p>
                    {model.specs && (
                      <p className="text-xs text-muted-foreground mt-1 line-clamp-2">
                        {model.specs}
                      </p>
                    )}
                    <div className="flex items-center justify-between mt-3 pt-3 border-t">
                      {user.role === "IT_ADMIN" && (
                        <span className="text-sm font-bold text-primary">
                          ¥{model.purchasePrice.toLocaleString()}
                        </span>
                      )}
                      <span className="text-xs text-muted-foreground">
                        库存: {model.stockCount} | 保修: {model.warrantyMonths}个月
                      </span>
                    </div>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        )}
      </div>
    </RoleGuard>
  );
}

