} from "lucide-react";

/* ---------- static mock data ---------- */

type UserRole = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
type UserStatus = "ACTIVE" | "INACTIVE";

interface UserItem {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  department: string;
  status: UserStatus;
  assetCount: number;
}

const roleLabels: Record<UserRole, string> = {
  EMPLOYEE: "员工",
  MANAGER: "主管",
  IT_ADMIN: "IT管理员",
  EXECUTIVE: "高管",
};

const roleVariants: Record<UserRole, "blue" | "orange" | "purple" | "green"> = {
  EMPLOYEE: "blue",
  MANAGER: "orange",
  IT_ADMIN: "purple",
  EXECUTIVE: "green",
};

const mockUsers: UserItem[] = [
  { id: "user-001", name: "张明", email: "zhangming@company.com", role: "EMPLOYEE", department: "研发部", status: "ACTIVE", assetCount: 2 },
  { id: "user-002", name: "李主管", email: "lizhu@company.com", role: "MANAGER", department: "研发部", status: "ACTIVE", assetCount: 1 },
  { id: "user-003", name: "王工", email: "wanggong@company.com", role: "IT_ADMIN", department: "IT部", status: "ACTIVE", assetCount: 0 },
  { id: "user-004", name: "赵总", email: "zhaoz@company.com", role: "EXECUTIVE", department: "总经办", status: "ACTIVE", assetCount: 1 },
  { id: "user-005", name: "陈芳", email: "chenfang@company.com", role: "EMPLOYEE", department: "设计部", status: "ACTIVE", assetCount: 1 },
  { id: "user-006", name: "刘阳", email: "liuyang@company.com", role: "EMPLOYEE", department: "研发部", status: "INACTIVE", assetCount: 0 },
];

/* ---------- component ---------- */

export default function ITUsersPage() {
  const [search, setSearch] = useState("");
  const [departmentFilter, setDepartmentFilter] = useState("");

  const departments = [...new Set(mockUsers.map((u) => u.department))];

  const filtered = mockUsers.filter((u) => {
    const matchSearch =
      !search ||
      u.name.includes(search) ||
      u.email.toLowerCase().includes(search.toLowerCase());
    const matchDept = !departmentFilter || u.department === departmentFilter;
    return matchSearch && matchDept;
  });

  // Group by department
  const grouped = filtered.reduce<Record<string, UserItem[]>>((acc, u) => {
    (acc[u.department] ||= []).push(u);
    return acc;
  }, {});

  return (
    <RoleGuard roles={["IT_ADMIN"]}>
      <div className="max-w-5xl mx-auto space-y-6">
        <div className="flex items-center justify-between flex-wrap gap-2">
