          </div>
          <Button size="sm" disabled>
            新增用户
          </Button>
        </div>

        {/* Filters */}
        <Card>
          <CardContent className="p-4">
            <div className="flex flex-wrap gap-3 items-center">
              <div className="flex items-center gap-1 flex-1 min-w-0 max-w-sm">
                <Search className="w-4 h-4 text-muted-foreground shrink-0" />
                <Input
                  placeholder="搜索姓名或邮箱..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="h-8 text-sm"
                />
              </div>
              <select
                value={departmentFilter}
                onChange={(e) => setDepartmentFilter(e.target.value)}
                className="text-sm border rounded-md px-3 py-1.5 bg-background"
              >
                <option value="">全部部门</option>
                {departments.map((d) => (
                  <option key={d} value={d}>
                    {d}
                  </option>
                ))}
              </select>
            </div>
          </CardContent>
        </Card>

        {/* User list by department */}
        {Object.keys(grouped).length === 0 ? (
          <Card>
            <CardContent className="py-12 text-center text-muted-foreground">
              <Users className="w-12 h-12 mx-auto mb-3 opacity-30" />
              <p className="text-sm">暂无匹配的用户</p>
            </CardContent>
          </Card>
        ) : (
          Object.entries(grouped).map(([dept, users]) => (
            <Card key={dept}>
              <CardHeader>
                <CardTitle className="text-sm flex items-center gap-2">
                  <Building2 className="w-4 h-4 text-muted-foreground" />
                  {dept}
                  <Badge variant="gray" className="ml-1">
                    {users.length}人
                  </Badge>
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  {users.map((u) => (
                    <div
                      key={u.id}
                      className="flex items-center justify-between p-3 rounded-lg hover:bg-muted transition-colors"
                    >
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center">
                          <User className="w-4 h-4 text-muted-foreground" />
                        </div>
                        <div>
                          <div className="flex items-center gap-2">
                            <span className="text-sm font-medium">{u.name}</span>
                            <Badge variant={roleVariants[u.role]}>
                              {roleLabels[u.role]}
                            </Badge>
                            {u.status === "INACTIVE" && (
                              <Badge variant="gray">已禁用</Badge>
                            )}
                          </div>
                          <div className="flex items-center gap-2 text-xs text-muted-foreground mt-0.5">
                            <Mail className="w-3 h-3" />
                            {u.email}
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center gap-4 text-sm">
                        <span className="text-muted-foreground">
                          <Shield className="w-3 h-3 inline mr-1" />
