                    <div className="min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="text-sm font-medium">
                          {actionLabels[log.action] || log.action}
                        </span>
                        <Badge variant="gray" className="text-xs">
                          {targetTypeLabels[log.targetType] || log.targetType}
                        </Badge>
                        <span className="text-xs font-mono text-muted-foreground">
                          {log.targetId}
                        </span>
                      </div>
                      <div className="flex items-center gap-2 text-xs text-muted-foreground mt-0.5">
                        <span className="flex items-center gap-1">
                          <User className="w-3 h-3" />
                          {log.operatorName}
                        </span>
                        {log.fromStatus && log.toStatus && (
                          <span>
                            {log.fromStatus} &rarr; {log.toStatus}
                          </span>
                        )}
                        {log.metadata && (
                          <span className="truncate max-w-48">"{log.metadata}"</span>
                        )}
                      </div>
                    </div>
                  </div>
                  <span className="text-xs text-muted-foreground shrink-0 ml-2 flex items-center gap-1">
                    <Clock className="w-3 h-3" />
                    {log.createdAt}
                  </span>
                </div>
              ))}
            </CardContent>
          </Card>
        )}

        {/* Pagination placeholder */}
