          <Button variant="outline" size="sm" disabled>
            上一页
          </Button>
          <span className="text-sm text-muted-foreground">1 / 1</span>
          <Button variant="outline" size="sm" disabled>
            下一页
          </Button>
        </div>
      </div>
    </RoleGuard>
  );
}

